    return ListView.builder(
      itemCount: _trustedPeers.length,
      itemBuilder: (context, index) {
        final peer = _trustedPeers[index];

        return Card(
          elevation: 0,
          color: const Color(0xFF0F172A),
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(8),
            side: BorderSide(color: Slate.c800),
          ),
          margin: const EdgeInsets.symmetric(vertical: 4),
          child: ListTile(
            dense: true,
            title: Text(peer.deviceName, style: const TextStyle(fontWeight: FontWeight.bold)),
            subtitle: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const SizedBox(height: 4),
                Text('FP: ${peer.fingerprint}', style: const TextStyle(fontSize: 10, fontFamily: 'monospace', color: Colors.amber)),
                const SizedBox(height: 2),
                Text('ID: ${peer.deviceId}', style: TextStyle(fontSize: 10, color: Slate.c500, fontFamily: 'monospace')),
              ],
            ),
            trailing: IconButton(
              icon: const Icon(Icons.delete_forever, color: Colors.redAccent),
              onPressed: () {
                _showUnpairConfirmation(peer.deviceId, peer.deviceName);
              },
            ),
          ),
        );
      },
    );
  }

  void _showUnpairConfirmation(String peerId, String name) {
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text("Confirm Unpair"),
        content: Text("Are you sure you want to unpair from $name? Secure sessions will be immediately terminated."),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context),
            child: const Text("Cancel"),
          ),
          ElevatedButton(
            onPressed: () {
              api.unpairDevice(peerId: peerId);
              Navigator.pop(context);
              _log("Device $name unpaired and untrusted.");
            },
            style: ElevatedButton.styleFrom(backgroundColor: Colors.red),
            child: const Text("Unpair"),
          ),
        ],
      ),
    );
  }
}
